      "classification": "potential-vulnerability",
      "code_path": "src/GPV2CompatibleAuction.sol::isValidSignature::L119-176",
      "proof_trace": "BaseAuction.bid() enforces minBidUsdValue at L431-435, but the alternative CowSwap settlement path (GPV2CompatibleAuction.isValidSignature) only checks order.sellAmount > 0 and buyAmount >= minBuyAmount(sellAmount) \u2014 it never compares the sell amount's USD value against s_minBidUsdValue. CowSwap settlement calls isValidSignature then directly transfers tokens via the vault relayer without invoking bid(), so the minimum bid USD threshold is not enforced on this path.",
      "attack_scenario": "A CowSwap solver constructs a partial order with order.sellAmount = 1 wei, sets buyAmount to the proportional _getAssetOutAmount result, and submits to CowSwap settlement; isValidSignature validates and the settlement executes, taking 1 wei of the auctioned asset while bypassing the s_minBidUsdValue check entirely.",
      "checklist_id": "PROP-01b-partial-pre-002"
    },
    "text": "Bid USD value must meet minimum threshold (minBidUsdValue).",
    "assertion": "forall bid(asset, amount): bidUsdValue(amount, price) >= s_minBidUsdValue",
    "covers": "SG-003",
    "severity": "MEDIUM",
    "type": "pre-condition"
  }
}

